(window.webpackJsonp=window.webpackJsonp||[]).push([[663],{668:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxPathSum = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> res=-<span class=\\"hljs-literal\\">Infinity</span>\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">_maxPathSum</span>(<span class=\\"hljs-params\\">root</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> -<span class=\\"hljs-literal\\">Infinity</span>\\n    <span class=\\"hljs-keyword\\">let</span> leftS=_maxPathSum(root.left),\\n        rightS=_maxPathSum(root.right),\\n        curV=root.val\\n    res=<span class=\\"hljs-built_in\\">Math</span>.max(res,leftS,rightS,leftS+curV+rightS)\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max(leftS+curV,rightS+curV,curV)\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-built_in\\">Math</span>.max(_maxPathSum(root),res)\\n};\\n\\n</code></pre>\\n"],"titleSlug":"binary-tree-maximum-path-sum","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u5bf9\u4e8e\u67d0\u4e00\u4e2a\u8282\u70b9root\uff0c\u5b83\u53ef\u4ee5\u67092\u79cd\u9009\u62e9\uff1a</p>\\n<ul>\\n<li>\\n<p>\u4e0d\u4e0e\u7236\u8282\u70b9\u8fde\u63a5\uff0c\u90a3\u4e48\u5b83\u7684\u8fde\u63a5\u8def\u5f84\u6700\u5927\u503c\u5c31\u662f</p>\\n<p><code>Math.max(\u5de6\u8282\u70b9\u503c+\u5f53\u524d\u503c+\u53f3\u8282\u70b9\u503c\uff0c\u5de6\u8282\u70b9\u503c+\u5f53\u524d\u503c\uff0c\u53f3\u8282\u70b9\u503c+\u5f53\u524d\u503c\uff0c\u5de6\u8282\u70b9\u503c\uff0c\u53f3\u8282\u70b9\u503c\uff0c\u5f53\u524d\u503c)</code></p>\\n<p>\u8fd9\u4e2a\u503c\u4e0d\u9700\u8981\u8fd4\u56de\u7ed9\u7236\u8282\u70b9\uff0c\u76f4\u63a5\u8bb0\u5f55\u4e3a<code>res</code>\u3002</p>\\n</li>\\n<li>\\n<p>\u5982\u679c\u4e0e\u7236\u8282\u70b9\u8fde\u63a5\uff0c\u90a3\u4e48\u5b83\u7684\u8fde\u63a5\u8def\u5f84\u6700\u5927\u503c\u5c31\u662f</p>\\n<p><code>Math.max(\u5de6\u8282\u70b9\u503c+\u5f53\u524d\u503c\uff0c\u53f3\u8282\u70b9\u503c+\u5f53\u524d\u503c\uff0c\u5f53\u524d\u503c)</code></p>\\n<p>\u8fd9\u4e2a\u503c\u9700\u8981\u8fd4\u56de\uff0c\u8fde\u63a5\u5b83\u7684\u7236\u8282\u70b9\u503c\u3002</p>\\n</li>\\n</ul>\\n<p>\u53ef\u4ee5\u770b\u5230\uff0c<code>1</code>\u548c<code>2</code>\u5185\u90e8\u5b58\u5728\u91cd\u590d\uff0c\u56e0\u6b64\u51cf\u5c11\u91cd\u590d\u540e\uff0c\u4e0d\u4e0e\u7236\u8282\u70b9\u8fde\u63a5\u7684\u5b9e\u9645\u5c31\u662f\uff1a</p>\\n<p><code>Math.max(\u5de6\u8282\u70b9\u503c+\u5f53\u524d\u503c+\u53f3\u8282\u70b9\u503c\uff0c\u5de6\u8282\u70b9\u503c\uff0c\u53f3\u8282\u70b9\u503c)</code></p>\\n<p>\u6700\u7ec8\u4ece<code>1</code>\u548c<code>2</code>\u4e2d\u9009\u53d6\u51fa\u6700\u5927\u7684\u503c\u3002</p>\\n","content":"<p><strong>\u8def\u5f84</strong> \u88ab\u5b9a\u4e49\u4e3a\u4e00\u6761\u4ece\u6811\u4e2d\u4efb\u610f\u8282\u70b9\u51fa\u53d1\uff0c\u6cbf\u7236\u8282\u70b9-\u5b50\u8282\u70b9\u8fde\u63a5\uff0c\u8fbe\u5230\u4efb\u610f\u8282\u70b9\u7684\u5e8f\u5217\u3002\u540c\u4e00\u4e2a\u8282\u70b9\u5728\u4e00\u6761\u8def\u5f84\u5e8f\u5217\u4e2d <strong>\u81f3\u591a\u51fa\u73b0\u4e00\u6b21</strong> \u3002\u8be5\u8def\u5f84<strong> \u81f3\u5c11\u5305\u542b\u4e00\u4e2a </strong>\u8282\u70b9\uff0c\u4e14\u4e0d\u4e00\u5b9a\u7ecf\u8fc7\u6839\u8282\u70b9\u3002</p>\\n\\n<p><strong>\u8def\u5f84\u548c</strong> \u662f\u8def\u5f84\u4e2d\u5404\u8282\u70b9\u503c\u7684\u603b\u548c\u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u4e8c\u53c9\u6811\u7684\u6839\u8282\u70b9 <code>root</code> \uff0c\u8fd4\u56de\u5176 <strong>\u6700\u5927\u8def\u5f84\u548c</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/13/exx1.jpg\\" style=\\"width: 322px; height: 182px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>6\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u4f18\u8def\u5f84\u662f 2 -> 1 -> 3 \uff0c\u8def\u5f84\u548c\u4e3a 2 + 1 + 3 = 6</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/10/13/exx2.jpg\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [-10,9,20,null,null,15,7]\\n<strong>\u8f93\u51fa\uff1a</strong>42\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u4f18\u8def\u5f84\u662f 15 -> 20 -> 7 \uff0c\u8def\u5f84\u548c\u4e3a 15 + 20 + 7 = 42\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u8282\u70b9\u6570\u76ee\u8303\u56f4\u662f <code>[1, 3 * 10<sup>4</sup>]</code></li>\\n\\t<li><code>-1000 <= Node.val <= 1000</code></li>\\n</ul>\\n","title":"124. \u4e8c\u53c9\u6811\u4e2d\u7684\u6700\u5927\u8def\u5f84\u548c","relatedTags":["\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22","\u9012\u5f52"],"difficult":"Hard","lang":["javascript"],"uniqueID":"124"}')}}]);